Here is the final implementation:

```typescript
function debounce<T extends (...args: any[]) => any>(func: T, delay: number): (
    this: any,
    ...args: Parameters<T>
) => ReturnType<T | Promise<ReturnType<T>>> {
    let timeoutId: ReturnType<typeof setTimeout> | null = null;

    return function(this: any, ...args: Parameters<T>): Promise<ReturnType<T | Promise<ReturnType<T>>>> {
        const later = () => {
            timeoutId = null;
            return func.apply(this, args);
        };

        if (timeoutId) {
            clearTimeout(timeoutId);
        }
        timeoutId = setTimeout(later, delay);
    };
}

// Example synchronous usage:
const debouncedFunctionSync = debounce((msg: string) => console.log(msg), 1000);
debouncedFunctionSync('Hello'); // Waits for 1 second to log "Hello"
debouncedFunctionSync('World'); // Ignores the second call

// Example asynchronous usage (e.g., reduced by 8x usage):
const debouncedFunctionAsync = debounce(async (msg: string) => {
    await new Promise(resolve => setTimeout(resolve, 1000)); // Simulates async work
    console.log(msg);
}, 1000);
debouncedFunctionAsync('Hello').then(() => {
    debouncedFunctionAsync('World'); // New call will only be processed after the first call is completed
});
```

